69: Network::FilterStatus UdpProxyFilter::onData(Network::UdpRecvData& data) {
70:   const std::string& route = config_->route(*data.addresses_.local_, *data.addresses_.peer_);
71:   if (!cluster_infos_.contains(route)) {
72:     config_->stats().downstream_sess_no_route_.inc();
73:     return Network::FilterStatus::StopIteration;
74:   }
75: 
76:   return cluster_infos_[route]->onData(data);
77: }
