79: Network::FilterStatus UdpProxyFilter::onReceiveError(Api::IoError::IoErrorCode) {
80:   config_->stats().downstream_sess_rx_errors_.inc();
81: 
82:   return Network::FilterStatus::StopIteration;
83: }
