270: class HttpUpstreamImpl : public HttpUpstream, protected Http::StreamCallbacks {
271: public:
272:   HttpUpstreamImpl(UpstreamTunnelCallbacks& upstream_callbacks, const UdpTunnelingConfig& config,
273:                    StreamInfo::StreamInfo& downstream_info)
274:       : response_decoder_(*this), upstream_callbacks_(upstream_callbacks),
275:         downstream_info_(downstream_info), tunnel_config_(config) {}
276:   ~HttpUpstreamImpl() override;
277: 
278:   Http::ResponseDecoder& responseDecoder() { return response_decoder_; }
279:   void setRequestEncoder(Http::RequestEncoder& request_encoder, bool is_ssl);
280:   void setTunnelCreationCallbacks(TunnelCreationCallbacks& callbacks) {
281:     tunnel_creation_callbacks_.emplace(callbacks);
282:   }
283: 
284:   // HttpUpstream
285:   void encodeData(Buffer::Instance& data) override;
286:   void onDownstreamEvent(Network::ConnectionEvent event) override {
287:     if (event == Network::ConnectionEvent::LocalClose ||
288:         event == Network::ConnectionEvent::RemoteClose) {
289:       resetEncoder(event, /*by_downstream=*/true);
290:     }
291:   };
292: 
293:   // Http::StreamCallbacks
294:   void onResetStream(Http::StreamResetReason, absl::string_view) override {
295:     resetEncoder(Network::ConnectionEvent::LocalClose);
296:   }
297: 
298:   void onAboveWriteBufferHighWatermark() override {
299:     upstream_callbacks_.onAboveWriteBufferHighWatermark();
300:   }
301: 
302:   void onBelowWriteBufferLowWatermark() override {
303:     upstream_callbacks_.onBelowWriteBufferLowWatermark();
304:   }
305: 
306: private:
307:   class ResponseDecoder : public Http::ResponseDecoder {
308:   public:
309:     ResponseDecoder(HttpUpstreamImpl& parent) : parent_(parent) {}
310: 
311:     // Http::ResponseDecoder
312:     void decodeMetadata(Http::MetadataMapPtr&&) override {}
313:     void decode1xxHeaders(Http::ResponseHeaderMapPtr&&) override {}
314:     void dumpState(std::ostream& os, int indent_level) const override {
315:       DUMP_STATE_UNIMPLEMENTED(ResponseDecoder);
316:     }
317: 
318:     void decodeHeaders(Http::ResponseHeaderMapPtr&& headers, bool end_stream) override {
319:       bool is_valid_response;
320:       if (parent_.tunnel_config_.usePost()) {
321:         auto status = Http::Utility::getResponseStatus(*headers);
322:         is_valid_response = Http::CodeUtility::is2xx(status);
323:       } else {
324:         is_valid_response = Http::HeaderUtility::isConnectUdpResponse(*headers);
325:       }
326: 
327:       parent_.tunnel_config_.propagateResponseHeaders(std::move(headers),
328:                                                       parent_.downstream_info_.filterState());
329: 
330:       if (!is_valid_response || end_stream) {
331:         parent_.resetEncoder(Network::ConnectionEvent::LocalClose);
332:       } else if (parent_.tunnel_creation_callbacks_.has_value()) {
333:         parent_.tunnel_creation_callbacks_.value().get().onStreamSuccess(*parent_.request_encoder_);
334:         parent_.tunnel_creation_callbacks_.reset();
335:       }
336:     }
337: 
338:     void decodeData(Buffer::Instance& data, bool end_stream) override {
339:       parent_.upstream_callbacks_.onUpstreamData(data, end_stream);
340:       if (end_stream) {
341:         parent_.resetEncoder(Network::ConnectionEvent::LocalClose);
342:       }
343:     }
344: 
345:     void decodeTrailers(Http::ResponseTrailerMapPtr&& trailers) override {
346:       parent_.tunnel_config_.propagateResponseTrailers(std::move(trailers),
347:                                                        parent_.downstream_info_.filterState());
348:       parent_.resetEncoder(Network::ConnectionEvent::LocalClose);
349:     }
350: 
351:   private:
352:     HttpUpstreamImpl& parent_;
353:   };
354: 
355:   const std::string resolveTargetTunnelPath();
356:   void resetEncoder(Network::ConnectionEvent event, bool by_downstream = false);
357: 
358:   ResponseDecoder response_decoder_;
359:   Http::RequestEncoder* request_encoder_{};
360:   UpstreamTunnelCallbacks& upstream_callbacks_;
361:   StreamInfo::StreamInfo& downstream_info_;
362:   const UdpTunnelingConfig& tunnel_config_;
363:   absl::optional<std::reference_wrapper<TunnelCreationCallbacks>> tunnel_creation_callbacks_;
364: };
