725:   struct HeterogeneousActiveSessionHash {
726:     // Specifying is_transparent indicates to the library infrastructure that
727:     // type-conversions should not be applied when calling find(), but instead
728:     // pass the actual types of the contained and searched-for objects directly to
729:     // these functors. See
730:     // https://en.cppreference.com/w/cpp/utility/functional/less_void for an
731:     // official reference, and https://abseil.io/tips/144 for a description of
732:     // using it in the context of absl.
733:     using is_transparent = void; // NOLINT(readability-identifier-naming)
734: 
735:     HeterogeneousActiveSessionHash(const bool consider_host) : consider_host_(consider_host) {}
736: 
737:     size_t operator()(const Network::UdpRecvData::LocalPeerAddresses& value) const {
738:       return absl::Hash<const Network::UdpRecvData::LocalPeerAddresses>()(value);
739:     }
740:     size_t operator()(const LocalPeerHostAddresses& value) const {
741:       auto hash = this->operator()(value.local_peer_addresses_);
742:       if (consider_host_) {
743:         hash = absl::HashOf(hash, value.host_.value().get().address()->asStringView());
744:       }
745:       return hash;
746:     }
747:     size_t operator()(const ActiveSession* value) const {
748:       LocalPeerHostAddresses key{value->addresses(), value->host()};
749:       return this->operator()(key);
750:     }
751:     size_t operator()(const ActiveSessionPtr& value) const { return this->operator()(value.get()); }
752: 
753:   private:
754:     const bool consider_host_;
755:   };
756: 
757:   struct HeterogeneousActiveSessionEqual {
758:     // See description for HeterogeneousActiveSessionHash::is_transparent.
759:     using is_transparent = void; // NOLINT(readability-identifier-naming)
760: 
761:     HeterogeneousActiveSessionEqual(const bool consider_host) : consider_host_(consider_host) {}
762: 
763:     bool operator()(const ActiveSessionPtr& lhs,
764:                     const Network::UdpRecvData::LocalPeerAddresses& rhs) const {
765:       return lhs->addresses() == rhs;
766:     }
767:     bool operator()(const ActiveSessionPtr& lhs, const LocalPeerHostAddresses& rhs) const {
768:       return this->operator()(lhs, rhs.local_peer_addresses_) &&
769:              (consider_host_ ? &lhs->host().value().get() == &rhs.host_.value().get() : true);
770:     }
771:     bool operator()(const ActiveSessionPtr& lhs, const ActiveSession* rhs) const {
772:       LocalPeerHostAddresses key{rhs->addresses(), rhs->host()};
773:       return this->operator()(lhs, key);
774:     }
775:     bool operator()(const ActiveSessionPtr& lhs, const ActiveSessionPtr& rhs) const {
776:       return this->operator()(lhs, rhs.get());
777:     }
778: 
779:   private:
780:     const bool consider_host_;
781:   };
