13: UdpProxyFilter::UdpProxyFilter(Network::UdpReadFilterCallbacks& callbacks,
14:                                const UdpProxyFilterConfigSharedPtr& config)
15:     : UdpListenerReadFilter(callbacks), config_(config),
16:       cluster_update_callbacks_(
17:           config->clusterManager().addThreadLocalClusterUpdateCallbacks(*this)) {
18:   for (const auto& entry : config_->allClusterNames()) {
19:     Upstream::ThreadLocalCluster* cluster = config->clusterManager().getThreadLocalCluster(entry);
20:     if (cluster != nullptr) {
21:       Upstream::ThreadLocalClusterCommand command = [&cluster]() -> Upstream::ThreadLocalCluster& {
22:         return *cluster;
23:       };
24:       onClusterAddOrUpdate(cluster->info()->name(), command);
25:     }
26:   }
27: 
28:   if (!config_->proxyAccessLogs().empty()) {
29:     udp_proxy_stats_.emplace(StreamInfo::StreamInfoImpl(
30:         config_->timeSource(), nullptr, StreamInfo::FilterState::LifeSpan::Connection));
31:   }
32: }
