34: UdpProxyFilter::~UdpProxyFilter() {
35:   if (!config_->proxyAccessLogs().empty()) {
36:     fillProxyStreamInfo();
37:     for (const auto& access_log : config_->proxyAccessLogs()) {
38:       access_log->log({}, udp_proxy_stats_.value());
39:     }
40:   }
41: }
