60: void UdpProxyFilter::onClusterRemoval(const std::string& cluster) {
61:   if (!cluster_infos_.contains(cluster)) {
62:     return;
63:   }
64: 
65:   ENVOY_LOG(debug, "udp proxy: detaching from cluster {}", cluster);
66:   cluster_infos_.erase(cluster);
67: }
