85: UdpProxyFilter::ClusterInfo::ClusterInfo(UdpProxyFilter& filter,
86:                                          Upstream::ThreadLocalCluster& cluster,
87:                                          SessionStorageType&& sessions)
88:     : filter_(filter), cluster_(cluster),
89:       cluster_stats_(generateStats(cluster.info()->statsScope())), sessions_(std::move(sessions)),
90:       member_update_cb_handle_(cluster.prioritySet().addMemberUpdateCb(
91:           [this](const Upstream::HostVector&, const Upstream::HostVector& hosts_removed) {
92:             for (const auto& host : hosts_removed) {
93:               // This is similar to removeSession() but slightly different due to removeSession()
94:               // also handling deletion of the host to session map entry if there are no sessions
95:               // left. It would be nice to unify the logic but that can be cleaned up later.
96:               auto host_sessions_it = host_to_sessions_.find(host.get());
97:               if (host_sessions_it != host_to_sessions_.end()) {
98:                 for (auto& session : host_sessions_it->second) {
99:                   session->onSessionComplete();
100:                   ASSERT(sessions_.count(session) == 1);
101:                   sessions_.erase(session);
102:                 }
103:                 host_to_sessions_.erase(host_sessions_it);
104:               }
105:             }
106:           })) {}
107: 
108: UdpProxyFilter::ClusterInfo::~ClusterInfo() {
109:   // Sanity check the session accounting. This is not as fast as a straight teardown, but this is
110:   // not a performance critical path.
111:   while (!sessions_.empty()) {
112:     removeSession(sessions_.begin()->get());
113:   }
114:   ASSERT(host_to_sessions_.empty());
115: }
116: 
117: void UdpProxyFilter::ClusterInfo::removeSession(ActiveSession* session) {
118:   if (session->host().has_value()) {
119:     // First remove from the host to sessions map, in case the host was resolved.
120:     ASSERT(host_to_sessions_[&session->host().value().get()].count(session) == 1);
121:     auto host_sessions_it = host_to_sessions_.find(&session->host().value().get());
122:     host_sessions_it->second.erase(session);
123:     if (host_sessions_it->second.empty()) {
124:       host_to_sessions_.erase(host_sessions_it);
125:     }
126:   }
127: 
128:   session->onSessionComplete();
129: 
130:   // Now remove it from the primary map.
131:   ASSERT(sessions_.count(session) == 1);
132:   sessions_.erase(session);
133: }
