135: UdpProxyFilter::ActiveSession*
136: UdpProxyFilter::ClusterInfo::createSession(Network::UdpRecvData::LocalPeerAddresses&& addresses,
137:                                            const Upstream::HostConstSharedPtr& optional_host,
138:                                            bool defer_socket_creation) {
139:   if (!cluster_.info()
140:            ->resourceManager(Upstream::ResourcePriority::Default)
141:            .connections()
142:            .canCreate()) {
143:     ENVOY_LOG(debug, "cannot create new connection.");
144:     cluster_.info()->trafficStats()->upstream_cx_overflow_.inc();
145:     return nullptr;
146:   }
147: 
148:   if (defer_socket_creation) {
149:     ASSERT(!optional_host);
150:     return createSessionWithOptionalHost(std::move(addresses), nullptr);
151:   }
152: 
153:   if (optional_host) {
154:     return createSessionWithOptionalHost(std::move(addresses), optional_host);
155:   }
156: 
157:   auto host = chooseHost(addresses.peer_, nullptr);
158:   if (host == nullptr) {
159:     ENVOY_LOG(debug, "cannot find any valid host.");
160:     cluster_.info()->trafficStats()->upstream_cx_none_healthy_.inc();
161:     return nullptr;
162:   }
163: 
164:   return createSessionWithOptionalHost(std::move(addresses), host);
165: }
166: 
167: UdpProxyFilter::ActiveSession* UdpProxyFilter::ClusterInfo::createSessionWithOptionalHost(
168:     Network::UdpRecvData::LocalPeerAddresses&& addresses,
169:     const Upstream::HostConstSharedPtr& host) {
170:   ActiveSessionPtr new_session;
171:   if (filter_.config_->tunnelingConfig()) {
172:     ASSERT(!host);
173:     new_session = std::make_unique<TunnelingActiveSession>(*this, std::move(addresses));
174:   } else {
175:     new_session = std::make_unique<UdpActiveSession>(*this, std::move(addresses), host);
176:   }
177: 
178:   new_session->createFilterChain();
179:   if (new_session->onNewSession()) {
180:     auto new_session_ptr = new_session.get();
181:     sessions_.emplace(std::move(new_session));
182:     return new_session_ptr;
183:   }
184: 
185:   new_session->onSessionComplete();
186:   return nullptr;
187: }
188: 
189: Upstream::HostConstSharedPtr UdpProxyFilter::ClusterInfo::chooseHost(
190:     const Network::Address::InstanceConstSharedPtr& peer_address,
191:     const StreamInfo::StreamInfo* stream_info) const {
192:   UdpLoadBalancerContext context(filter_.config_->hashPolicy(), peer_address, stream_info);
193:   Upstream::HostConstSharedPtr host = cluster_.loadBalancer().chooseHost(&context);
194:   return host;
195: }
