309: void UdpProxyFilter::ActiveSession::onSessionComplete() {
310:   ENVOY_LOG(debug, "deleting the session: downstream={} local={} upstream={}",
311:             addresses_.peer_->asStringView(), addresses_.local_->asStringView(),
312:             host_ != nullptr ? host_->address()->asStringView() : "unknown");
313: 
314:   cluster_.filter_.config_->stats().downstream_sess_active_.dec();
315:   cluster_.cluster_.info()
316:       ->resourceManager(Upstream::ResourcePriority::Default)
317:       .connections()
318:       .dec();
319: 
320:   disableAccessLogFlushTimer();
321: 
322:   for (auto& active_read_filter : read_filters_) {
323:     active_read_filter->read_filter_->onSessionComplete();
324:   }
325: 
326:   for (auto& active_write_filter : write_filters_) {
327:     active_write_filter->write_filter_->onSessionComplete();
328:   }
329: 
330:   if (!cluster_.filter_.config_->sessionAccessLogs().empty()) {
331:     fillSessionStreamInfo();
332:     const Formatter::HttpFormatterContext log_context{
333:         nullptr, nullptr, nullptr, {}, AccessLog::AccessLogType::UdpSessionEnd};
334:     for (const auto& access_log : cluster_.filter_.config_->sessionAccessLogs()) {
335:       access_log->log(log_context, udp_session_info_);
336:     }
337:   }
338: 
339:   on_session_complete_called_ = true;
340: }
