447: void UdpProxyFilter::ActiveSession::onData(Network::UdpRecvData& data) {
448:   ENVOY_LOG(trace, "received {} byte datagram from downstream: downstream={} local={} upstream={}",
449:             data.buffer_->length(), addresses_.peer_->asStringView(),
450:             addresses_.local_->asStringView(),
451:             host_ != nullptr ? host_->address()->asStringView() : "unknown");
452: 
453:   const uint64_t rx_buffer_length = data.buffer_->length();
454:   cluster_.filter_.config_->stats().downstream_sess_rx_bytes_.add(rx_buffer_length);
455:   session_stats_.downstream_sess_rx_bytes_ += rx_buffer_length;
456:   cluster_.filter_.config_->stats().downstream_sess_rx_datagrams_.inc();
457:   ++session_stats_.downstream_sess_rx_datagrams_;
458:   resetIdleTimer();
