470: void UdpProxyFilter::UdpActiveSession::writeUpstream(Network::UdpRecvData& data) {
471:   if (!udp_socket_) {
472:     ENVOY_LOG(debug, "cannot write upstream because the socket was not created.");
473:     return;
474:   }
475: 
476:   // NOTE: On the first write, a local ephemeral port is bound, and thus this write can fail due to
477:   //       port exhaustion. To avoid exhaustion, UDP sockets will be connected and associated with
478:   //       a 4-tuple including the local IP, and the UDP port may be reused for multiple
479:   //       connections unless use_original_src_ip_ is set. When use_original_src_ip_ is set, the
480:   //       socket should not be connected since the source IP will be changed.
481:   // NOTE: We do not specify the local IP to use for the sendmsg call if use_original_src_ip_ is not
482:   //       set. We allow the OS to select the right IP based on outbound routing rules if
483:   //       use_original_src_ip_ is not set, else use downstream peer IP as local IP.
484:   if (!connected_ && !use_original_src_ip_) {
485:     Api::SysCallIntResult rc = udp_socket_->ioHandle().connect(host_->address());
486:     if (SOCKET_FAILURE(rc.return_value_)) {
487:       ENVOY_LOG(debug, "cannot connect: ({}) {}", rc.errno_, errorDetails(rc.errno_));
488:       cluster_.cluster_stats_.sess_tx_errors_.inc();
489:       return;
490:     }
491: 
492:     connected_ = true;
493:   }
494: 
495:   ASSERT((connected_ || use_original_src_ip_) && udp_socket_ && host_);
496: 
497:   const uint64_t tx_buffer_length = data.buffer_->length();
498:   ENVOY_LOG(trace, "writing {} byte datagram upstream: downstream={} local={} upstream={}",
499:             tx_buffer_length, addresses_.peer_->asStringView(), addresses_.local_->asStringView(),
500:             host_->address()->asStringView());
501: 
502:   const Network::Address::Ip* local_ip = use_original_src_ip_ ? addresses_.peer_->ip() : nullptr;
503:   Api::IoCallUint64Result rc = Network::Utility::writeToSocket(
504:       udp_socket_->ioHandle(), *data.buffer_, local_ip, *host_->address());
505: 
506:   if (!rc.ok()) {
507:     cluster_.cluster_stats_.sess_tx_errors_.inc();
508:   } else {
509:     cluster_.cluster_stats_.sess_tx_datagrams_.inc();
510:     cluster_.cluster_.info()->trafficStats()->upstream_cx_tx_bytes_total_.add(tx_buffer_length);
511:   }
512: }
