514: bool UdpProxyFilter::ActiveSession::onContinueFilterChain(ActiveReadFilter* filter) {
515:   ASSERT(filter != nullptr);
516: 
517:   std::list<ActiveReadFilterPtr>::iterator entry = std::next(filter->entry());
518:   for (; entry != read_filters_.end(); entry++) {
519:     if (!(*entry)->read_filter_ || (*entry)->initialized_) {
520:       continue;
521:     }
522: 
523:     (*entry)->initialized_ = true;
524:     auto status = (*entry)->read_filter_->onNewSession();
525:     if (status == ReadFilterStatus::StopIteration) {
526:       return true;
527:     }
528:   }
529: 
530:   if (!createUpstream()) {
531:     cluster_.removeSession(this);
532:     return false;
533:   }
534: 
535:   return true;
536: }
