560: void UdpProxyFilter::UdpActiveSession::createUdpSocket(const Upstream::HostConstSharedPtr& host) {
561:   // NOTE: The socket call can only fail due to memory/fd exhaustion. No local ephemeral port
562:   //       is bound until the first packet is sent to the upstream host.
563:   udp_socket_ = cluster_.filter_.createUdpSocket(host);
564:   udp_socket_->ioHandle().initializeFileEvent(
565:       cluster_.filter_.read_callbacks_->udpListener().dispatcher(),
566:       [this](uint32_t) { onReadReady(); }, Event::PlatformDefaultTriggerType,
567:       Event::FileReadyType::Read);
568: 
569:   ENVOY_LOG(debug, "creating new session: downstream={} local={} upstream={}",
570:             addresses_.peer_->asStringView(), addresses_.local_->asStringView(),
571:             host->address()->asStringView());
572: 
573:   if (use_original_src_ip_) {
574:     const Network::Socket::OptionsSharedPtr socket_options =
575:         Network::SocketOptionFactory::buildIpTransparentOptions();
576:     const bool ok = Network::Socket::applyOptions(
577:         socket_options, *udp_socket_, envoy::config::core::v3::SocketOption::STATE_PREBIND);
578: 
579:     RELEASE_ASSERT(ok, "Should never occur!");
580:     ENVOY_LOG(debug, "The original src is enabled for address {}.",
581:               addresses_.peer_->asStringView());
582:   }
583: 
584:   // TODO(mattklein123): Enable dropped packets socket option. In general the Socket abstraction
585:   // does not work well right now for client sockets. It's too heavy weight and is aimed at listener
586:   // sockets. We need to figure out how to either refactor Socket into something that works better
587:   // for this use case or allow the socket option abstractions to work directly against an IO
588:   // handle.
589: }
