  test_sessions_[0].expectWriteToUpstream("hello2");
  recvDataFromDownstream("10.0.0.1:1000", "10.0.0.2:80", "hello2");
  EXPECT_EQ(1, config_->stats().downstream_sess_active_.value());
}

