    // Can't add pseudo header.
    header->set_key(":method");
    header->set_value("GET");
    EXPECT_THROW_WITH_MESSAGE(TunnelingConfigImpl(proto_config, context), EnvoyException,
                              ":-prefixed or host headers may not be modified");
  }

